export const generateListingText = async (
  data: PropertyData,
  mode: ListingMode
): Promise<string> => {
  const modelName = "gemini-2.5-flash";

  const templateToUse = mode === ListingMode.RENTAL ? RENTAL_TEMPLATE : SALE_TEMPLATE;
  const promptData = JSON.stringify(data);

  const prompt = `
    You are Linus, a Taiwanese Real Estate Agent in Tokyo.

    Task: Fill out the following ${mode} template based on the provided JSON data.

    ${TERMINOLOGY_GUIDE}

    Rules:
    1. **Tone**: Warm, Professional, Enthusiastic, "Taiwanese Human-touch".
    2. **Fact-Checking**: 
       - If a piece of information (like Auto-lock or specific equipment) is NOT in the JSON data, **DO NOT INVENT IT**.
       - Do not stick to old template defaults if the data contradicts or is missing.
    3. **Elevator Logic (Crucial)**:
       - **DO NOT** list "Elevator (電梯)" or "No Elevator" in the rigid metadata lines (e.g., do not put it in the "🏠 房屋亮點" section line).
       - **IF** the property has an elevator: You **MUST** include it as a bullet point in the **{Features_List}** section (e.g., "🛗 附設電梯，輕鬆搬家").
       - If no elevator: Do NOT mention it unless it is a specific selling point (e.g., 1st floor).
    4. **Formatting**:
       - **{Structure} / {Structure_Type}**: Insert structure type (e.g. RC造, SRC造, 木造) if available. If unknown, leave this placeholder empty.
       - **{Elevator_Info}** (For Sale Template Header): If elevator exists, write "電梯大樓". If not, leave blank.
       - **{Features_List}**: Keep this section **concise and simple**.
         - **DO NOT** use flowery adjectives, long descriptions, or marketing fluff for equipment.
         - Just list the equipment names directly.
         - Example: "系統廚具／獨立洗面台／浴室乾燥機／溫水洗淨便座／宅配箱"
         - **IMPORTANT: Use the full-width slash "／" to separate items. Do NOT use commas.**
       - Format money appropriately (e.g. 12.5萬).
    5. **Move-in/Handover Date**: Use the provided '{MoveInDate}' value. 
       - If Rental Mode: Use "即日入居可能" if "即入居".
       - If Sale Mode: Use term like "現況{MoveInDate}" or "引渡：{MoveInDate}".
    6. **Dynamic Hashtags**:
       - **IF RENTAL MODE**: Use tags like #東京租房 #日本留學 #打工渡假簽證.
       - **IF SALE MODE**: Use tags like #日本買房 #東京置產 #海外投資 #日本不動產 #TokyoRealEstate #東京公寓.
       - PLUS: Generate 3-5 tags specific to the {Station} and {Area} (e.g. #池袋生活 #新宿買房).
    7. **CRITICAL**: Do NOT use Markdown formatting (e.g., **bold** with asterisks). Output plain text only.

    Template:
    ${templateToUse}

    JSON Data:
    ${promptData}
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
    });
    return response.text || "Error generating text. Please try again.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return `Error connecting to AI service.\n\nTemplate Preview:\n${templateToUse}`;
  }
};

export const rewriteListingText = async (
  currentText: string,
  instruction: string
): Promise<string> => {
  const modelName = "gemini-2.5-flash";
  const prompt = `
    You are an expert copywriter for real estate.
    Rewrite the following listing text based on this instruction: "${instruction}".

    ${TERMINOLOGY_GUIDE}

    CRITICAL INSTRUCTIONS:
    1. Maintain the emojis and the general structure if possible.
    2. Adjust the tone and vocabulary to match the instruction.
    3. Keep the "Taiwanese Real Estate Agent in Japan" persona.
    4. **NO HALLUCINATIONS**: Do not add equipment (like elevators/auto-lock) that isn't already in the text, unless the user instruction explicitly asks to add it.
    5. OUTPUT ONLY THE REWRITTEN CONTENT. DO NOT include any conversational filler like "Here is the rewritten text:" or "Sure!". Just the text.
    6. **CRITICAL**: Do NOT use Markdown formatting (e.g., **bold** with asterisks). Output plain text only.
    7. **Formatting**: When listing features or equipment, use full-width slash "／" as separator.

    Original Text:
    ${currentText}
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
    });
    return response.text || currentText;
  } catch (error) {
    console.error("Rewrite Error:", error);
    return currentText;
  }
};

export const extractPropertyData = async (
  files: { mimeType: string; data: string }[],
  supplementaryText: string = ""
): Promise<Partial<PropertyData>> => {
  const modelName = "gemini-2.5-flash";

  const prompt = `
    Analyze the provided property documents (images or PDFs) and the supplementary user notes.
    Extract the following details into a JSON object.

    Supplementary User Notes (High Priority): ${supplementaryText}

    ${TERMINOLOGY_GUIDE}

    Instructions:
    1. **Strict Extraction**: If a field is not found in the documents or notes, leave it as an **empty string**. Do NOT guess.
    2. **Translation**: Translate Japanese terms to Traditional Chinese using the Terminology Mapping provided above.
       - Example: If you see 'オートロック', extract it as '大樓門禁'.
    3. **Price**: Extract the main rent or sale price (e.g., "12.5萬").
    4. **Financials**: 
       - If Rental: Look for '礼金' (Key Money) and '敷金' (Deposit).
       - If Sale: Look for '管理費' (Management Fee) and '修繕積立金' (Repair Fund).
    5. **Move-in/Handover Date (moveInDate)**: 
       - Look for '入居可能日', '現況', '引渡'.
       - **For Sale Properties (Usually under '現況' or '引渡')**:
         - If '空家' -> return "空室".
         - If '居住中' -> return "居住中".
         - If '賃貸中' -> return "賃貸中 (投資用)".
         - If '建築中' -> return "建築中".
         - If '即時', '即日', '即' -> return "即時".
       - **For Rental**: If '即入居', '即日' -> return "即入居".
       - If a specific date is found (e.g. 2024/10/01), return that date.
    6. **Features/Equipment**: Look for:
       - 'ペット' (Pets): If allowed (相談/可), MUST add "可養寵物" to features.
       - Equipment: Auto-lock (オートロック), Delivery Box (宅配ボックス), Bathroom Dryer (浴室乾燥), Stove type (2口コンロ), Elevator (エレベーター).
       - **Combine all found features into a string separated by "／" (full-width slash) using the translated terms.**

    Target Fields:
    - station: Station name
    - line: Train line
    - walkTime: Minutes to walk
    - price: Rent or Price
    - keyMoney: Key Money (礼金) - for rental
    - deposit: Deposit (敷金) - for rental
    - managementFee: Management Fee (管理費) - for sale
    - repairFund: Repair Fund (修繕積立金) - for sale
    - layout: Layout type (1LDK, etc.)
    - size: Size in m2
    - floor: Floor number
    - age: Building age/year
    - address: Address
    - moveInDate: Move-in available date or Sale Status (e.g. 即入居, 空室, 賃貸中)
    - features: Key features (include Pet info here if found)
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          ...files.map(f => ({ inlineData: f })),
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            station: { type: Type.STRING },
            line: { type: Type.STRING },
            walkTime: { type: Type.STRING },
            price: { type: Type.STRING },
            keyMoney: { type: Type.STRING },
            deposit: { type: Type.STRING },
            managementFee: { type: Type.STRING },
            repairFund: { type: Type.STRING },
            layout: { type: Type.STRING },
            size: { type: Type.STRING },
            floor: { type: Type.STRING },
            age: { type: Type.STRING },
            address: { type: Type.STRING },
            moveInDate: { type: Type.STRING },
            features: { type: Type.STRING },
          },
        }
      }
    });

    const text = response.text;
    if (!text) return {};
    return JSON.parse(text) as Partial<PropertyData>;
  } catch (error) {
    console.error("Gemini Extraction Error:", error);
    return {};
  }
};
